"use client";

/**
 * @file `AdminCollectionRegionPanel` — drawer tab body for a collection
 * that has at least one `<CollectionRegion>` binding on the current
 * page. Renders one sub-section per distinct filter on the page so a
 * page with two regions (`featured=true` + `tags=release`) shows both
 * lists side by side. A single shared "+ Yeni" form lives at the top
 * when the collection supports auto-generated slug creation.
 *
 * Each sub-section drives its own offset/limit state and accumulates
 * pages via "Load more". Filter parity with the page is enforced (the
 * panel uses exactly the filter the `<CollectionRegion>` declared);
 * limit/offset start at the page's values but the drawer extends
 * independently so the admin can paginate past the page's window.
 */

import { useEffect, useMemo, useRef, useState, useTransition } from "react";
import { ChevronDown, Undo2 } from "lucide-react";

import { useCmsContext } from "../lib/context.js";
import { useCollection } from "../hooks/use-collection.js";
import { useMyCollections } from "../hooks/use-my-collections.js";
import { CmsApiError } from "../lib/errors.js";
import { stableStringify } from "../lib/stable-stringify.js";

const DRAFT_DEBOUNCE_MS = 1000;
const NEW_DRAFT_GUID = "00000000-0000-0000-0000-000000000000";

import {
  AdminCollectionEditor,
  useCollectionEditor,
} from "./AdminCollectionEditor.jsx";
import {
  CollectionFieldsForm,
  seedValues,
  buildPayload,
  requiredMissing,
} from "./editors/CollectionFieldsForm.jsx";
import {
  TEXT_MUTED,
  TEXT_FAINT,
  COLLECTION_ACCENT,
  COLLECTION_SOFT,
  COLLECTION_LINE,
  BORDER,
  HAIRLINE,
  SURFACE_1,
  FONT_MONO,
  FONT_SANS,
  RADIUS,
  TYPE_META,
  TYPE_STYLES,
  paneStyle,
  listStyle,
  emptyStateStyle,
  blockCardStyle,
  blockHeaderStyle,
  blockPathStyle,
  blockBodyStyle,
  blockResetStyle,
  blockTypeLabelStyle,
  dirtyDotStyle,
  typeIconStyle,
  btnPrimaryStyle,
  btnGhostStyle,
} from "./admin-drawer-styles.js";

const DEFAULT_DRAWER_PAGE_SIZE = 50;

/**
 * @param {{ collectionKey: string }} props
 */
export function AdminCollectionRegionPanel({ collectionKey }) {
  const { collectionBindings } = useCmsContext();
  const { collections: my } = useMyCollections();

  const meta = my.find((c) => c.collectionKey === collectionKey) ?? null;
  const canCreate = Boolean(meta?.canCreate);
  const isAutoGenerated = meta?.slugSource === "AutoGenerated";
  const supportsCreate = canCreate && isAutoGenerated;

  const sections = useMemo(() => {
    /** @type {Map<string, { filter: Record<string, *> | undefined, pageLimit: number | undefined, pageOffset: number | undefined }>} */
    const bySignature = new Map();
    for (const [, binding] of collectionBindings) {
      if (binding.slug) continue;
      if (binding.collection !== collectionKey) continue;
      const signature = stableStringify(binding.filter ?? null);
      if (bySignature.has(signature)) continue;
      bySignature.set(signature, {
        filter: binding.filter,
        pageLimit: binding.limit,
        pageOffset: binding.offset,
      });
    }
    return [...bySignature.entries()].map(([signature, info]) => ({ signature, ...info }));
  }, [collectionBindings, collectionKey]);

  return (
    // CreateForm stays pinned at the top; the scroll lane below owns
    // every RegionSection so the panel doesn't overflow the drawer's
    // clip box when enough items are open. Without this single-lane
    // pattern each section's inner ul fought for its own scrollbar and
    // the CreateForm got pushed past the visible area on busy pages.
    <section style={paneStyle}>
      {supportsCreate && meta?.schema ? (
        // Key on collectionKey so navigating between Collection tabs
        // remounts the form with fresh state instead of leaking the
        // previous tab's values / open flag into the new one.
        <CreateForm
          key={collectionKey}
          collectionKey={collectionKey}
          schema={meta.schema}
        />
      ) : null}

      <div style={regionScrollStyle}>
        {sections.length === 0 ? (
          <div style={emptyStateStyle}>
            Bu sayfa <code>{collectionKey}</code> için bir region binding'i göstermiyor.
          </div>
        ) : (
          sections.map((section) => (
            <RegionSection
              key={section.signature}
              collectionKey={collectionKey}
              filter={section.filter}
              pageLimit={section.pageLimit}
              pageOffset={section.pageOffset}
              showHeader={sections.length > 1 || section.filter !== undefined}
            />
          ))
        )}
      </div>
    </section>
  );
}

const regionScrollStyle = /** @type {React.CSSProperties} */ ({
  flex: 1,
  minHeight: 0,
  overflowY: "auto",
  scrollbarWidth: "none",
});

/**
 * @param {{
 *   collectionKey: string,
 *   filter: Record<string, *> | undefined,
 *   pageLimit: number | undefined,
 *   pageOffset: number | undefined,
 *   showHeader: boolean,
 * }} props
 */
function RegionSection({ collectionKey, filter, pageLimit, pageOffset, showHeader }) {
  const initialLimit = pageLimit ?? DEFAULT_DRAWER_PAGE_SIZE;
  const initialOffset = pageOffset ?? 0;
  const [offset, setOffset] = useState(initialOffset);
  const [limit] = useState(initialLimit);

  const filterKey = stableStringify(filter ?? null);
  const [accumulated, setAccumulated] = useState(
    /** @type {import("../lib/schemas.js").CollectionItemResponse[]} */ ([]),
  );

  const params = useMemo(
    () => ({
      ...(filter ? { filter } : {}),
      offset,
      limit,
    }),
    [filter, offset, limit],
  );
  const { items, total, isLoading, error, refetch } = useCollection(collectionKey, params);

  useEffect(() => {
    setOffset(initialOffset);
    setAccumulated([]);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [filterKey]);

  useEffect(() => {
    if (isLoading || error) return;
    if (offset === initialOffset) {
      setAccumulated(items);
    } else {
      setAccumulated((prev) => {
        const seen = new Set(prev.map((row) => row.slug));
        return [...prev, ...items.filter((row) => !seen.has(row.slug))];
      });
    }
  }, [items, isLoading, error, offset, initialOffset]);

  const canLoadMore = accumulated.length < total;
  const loadMore = () => setOffset((o) => o + limit);
  const remaining = Math.max(0, total - accumulated.length);

  return (
    <div style={sectionWrapStyle}>
      {showHeader ? (
        <RegionHeader filter={filter} loaded={accumulated.length} total={total} />
      ) : null}

      {error ? (
        <div style={errorBoxStyle}>
          <span style={{ flex: 1 }}>Liste alınamadı: {error.message}</span>
          <button
            type="button"
            onClick={refetch}
            className="inkly-text-button"
            style={retryTextStyle}
          >
            Yeniden dene
          </button>
        </div>
      ) : isLoading && accumulated.length === 0 ? (
        <div style={emptyStateStyle}>Yükleniyor…</div>
      ) : accumulated.length === 0 ? (
        <div style={emptyStateStyle}>Bu filtre için kayıt yok.</div>
      ) : (
        <ul style={listStyle} data-cms-list>
          {accumulated.map((item) => (
            <li key={item.id || item.slug} style={{ listStyle: "none" }}>
              <RegionItemCard
                collectionKey={collectionKey}
                slug={item.slug}
                canEdit={item.canEdit}
              />
            </li>
          ))}
        </ul>
      )}

      {canLoadMore ? (
        <button
          type="button"
          onClick={loadMore}
          disabled={isLoading}
          className="inkly-load-more"
          style={loadMoreStyle}
        >
          {isLoading ? "Yükleniyor…" : `Daha fazla yükle (${remaining} kalan)`}
        </button>
      ) : null}
    </div>
  );
}

/**
 * @param {{ filter: Record<string, *> | undefined, loaded: number, total: number }} props
 */
function RegionHeader({ filter, loaded, total }) {
  const summary = !filter || Object.keys(filter).length === 0
    ? "Filtresiz"
    : Object.entries(filter).map(([k, v]) => `${k}=${String(v)}`).join(" · ");
  return (
    <div style={regionHeaderStyle}>
      <span style={regionLabelStyle}>{summary}</span>
      <span style={regionCountStyle}>{loaded} / {total}</span>
    </div>
  );
}

/**
 * @param {{ collectionKey: string, slug: string, canEdit: boolean }} props
 */
function RegionItemCard({ collectionKey, slug, canEdit }) {
  const { activeCollectionItem, setActiveCollectionItem } = useCmsContext();
  const [isOpen, setIsOpen] = useState(false);
  const editor = useCollectionEditor(collectionKey, slug);
  const isDirty = editor.hasDraft && editor.canEdit;

  // Honour the StatusBar "Aç" jump: when context targets this exact row,
  // open it once and clear the signal so re-visiting the tab doesn't keep
  // forcing the card open after the user closes it manually.
  useEffect(() => {
    if (!activeCollectionItem) return;
    if (activeCollectionItem.key !== collectionKey) return;
    if (activeCollectionItem.slug !== slug) return;
    setIsOpen(true);
    setActiveCollectionItem(null);
  }, [activeCollectionItem, collectionKey, slug, setActiveCollectionItem]);

  return (
    <div
      className={`inkly-block-card inkly-block-card-collection${isDirty ? " is-dirty" : ""}${isOpen ? " inkly-block-card-collection-active" : ""}`}
      style={blockCardStyle}
    >
      <button
        type="button"
        onClick={() => setIsOpen((v) => !v)}
        aria-expanded={isOpen}
        style={{
          ...blockHeaderStyle,
          width: "100%",
          cursor: "pointer",
          userSelect: "none",
          textAlign: "left",
          fontFamily: "inherit",
          color: "inherit",
        }}
      >
        <TypeIconCollection />
        <span style={blockPathStyle} title={slug}>{slug}</span>

        {!canEdit ? <span style={readonlyChipStyle}>readonly</span> : null}

        {isDirty ? (
          <span
            style={{ ...dirtyDotStyle, background: COLLECTION_ACCENT, boxShadow: `0 0 5px ${COLLECTION_ACCENT}80` }}
            aria-label="Kaydedilmemiş değişiklik"
          />
        ) : null}

        {isDirty ? (
          <span
            role="button"
            tabIndex={0}
            onClick={(e) => { e.stopPropagation(); editor.undoDraft(); }}
            onKeyDown={(e) => {
              if (e.key === "Enter" || e.key === " ") {
                e.preventDefault();
                e.stopPropagation();
                editor.undoDraft();
              }
            }}
            className="inkly-icon-button"
            style={blockResetStyle}
            aria-label="Bu kaydın değişikliklerini geri al"
            title="Geri al"
          >
            <Undo2 size={13} />
          </span>
        ) : null}

        <span style={blockTypeLabelStyle}>{TYPE_META.Collection.label}</span>

        <span
          style={{
            display: "inline-flex",
            color: TEXT_MUTED,
            transition: "transform 220ms cubic-bezier(0.32, 0.72, 0.18, 1)",
            transform: isOpen ? "rotate(180deg)" : "rotate(0deg)",
          }}
        >
          <ChevronDown size={13} />
        </span>
      </button>

      <div
        className={`inkly-collapse${isOpen ? " is-open" : ""}`}
        aria-hidden={!isOpen}
      >
        <div style={blockBodyStyle}>
          <AdminCollectionEditor editor={editor} showMetaRow={false} />
        </div>
      </div>
    </div>
  );
}

function TypeIconCollection() {
  const meta = TYPE_META.Collection;
  const styles = TYPE_STYLES.Collection;
  return (
    <span
      aria-hidden="true"
      style={{
        ...typeIconStyle,
        color: meta.color,
        background: styles.bg,
      }}
    >
      {meta.glyph}
    </span>
  );
}

/**
 * @param {{ collectionKey: string, schema: import("../lib/schemas.js").CollectionSchema }} props
 */
function CreateForm({ collectionKey, schema }) {
  const { config, getAccessToken, updateCollectionItem } = useCmsContext();
  const [isOpen, setIsOpen] = useState(false);
  const [values, setValues] = useState(() => seedValues(schema.fields, {}));
  const [error, setError] = useState(/** @type {string | null} */ (null));
  const [isPending, startTransition] = useTransition();
  const [draftStatus, setDraftStatus] = useState(
    /** @type {"idle"|"saving"|"saved"|"failed"} */ ("idle"),
  );

  const { items: unfiltered } = useCollection(collectionKey);
  const draftEntry = useMemo(
    () => unfiltered.find((row) => row.id === NEW_DRAFT_GUID) ?? null,
    [unfiltered],
  );
  const draftData = draftEntry?.draftData ?? null;

  const lastSyncedRef = useRef(/** @type {string | null} */ (null));
  const draftStatusResetRef = useRef(
    /** @type {ReturnType<typeof setTimeout>|null} */ (null),
  );

  // Seed the form from the backend draft once it arrives. Only seed
  // on the null → object flip so a successful publish (which clears
  // the draft) doesn't immediately re-seed against the just-emptied
  // values.
  const seededRef = useRef(false);
  useEffect(() => {
    if (seededRef.current) return;
    if (!draftData) return;
    setValues(seedValues(schema.fields, draftData));
    lastSyncedRef.current = stableStringify(draftData);
    seededRef.current = true;
    setIsOpen(true);
  }, [draftData, schema.fields]);

  useEffect(() => () => {
    if (draftStatusResetRef.current) clearTimeout(draftStatusResetRef.current);
  }, []);

  /** @param {"saved"|"failed"} kind */
  const flashDraftStatus = (kind) => {
    setDraftStatus(kind);
    if (draftStatusResetRef.current) clearTimeout(draftStatusResetRef.current);
    draftStatusResetRef.current = setTimeout(() => {
      setDraftStatus("idle");
      draftStatusResetRef.current = null;
    }, 900);
  };

  useEffect(() => {
    if (!isOpen) return undefined;
    if (isPending) return undefined;
    const payload = buildPayload(schema.fields, values);
    const serialized = stableStringify(payload);
    if (serialized === lastSyncedRef.current) return undefined;
    if (lastSyncedRef.current === null && serialized === stableStringify(buildPayload(schema.fields, seedValues(schema.fields, {})))) {
      return undefined;
    }

    let cancelled = false;
    const timer = setTimeout(async () => {
      try {
        const token = await getAccessToken();
        setDraftStatus("saving");
        await config.transport.saveCollectionNewDraft(collectionKey, { data: payload }, { accessToken: token });
        if (cancelled) return;
        lastSyncedRef.current = serialized;
        flashDraftStatus("saved");
      } catch (err) {
        if (cancelled) return;
        // eslint-disable-next-line no-console
        console.warn("[inkly] collection new-draft autosave failed:", err);
        flashDraftStatus("failed");
      }
    }, DRAFT_DEBOUNCE_MS);
    return () => {
      cancelled = true;
      clearTimeout(timer);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [values, isOpen, isPending, collectionKey]);

  const reset = () => {
    setValues(seedValues(schema.fields, {}));
    setError(null);
    lastSyncedRef.current = null;
    seededRef.current = false;
  };

  const undoDraft = () => {
    setError(null);
    setValues(seedValues(schema.fields, {}));
  };

  const submit = () => {
    setError(null);
    const missing = requiredMissing(schema.fields, values);
    if (missing) {
      setError(`Zorunlu alan eksik: ${missing}`);
      return;
    }
    startTransition(async () => {
      try {
        const token = await getAccessToken();
        const created = await config.transport.createCollectionItem(
          collectionKey,
          { data: buildPayload(schema.fields, values) },
          { accessToken: token },
        );
        updateCollectionItem(collectionKey, created.slug, created);
        reset();
        setIsOpen(false);
      } catch (err) {
        if (err instanceof CmsApiError && err.isForbidden) {
          setError("Bu collection'da kayıt oluşturma yetkin yok.");
        } else if (err instanceof CmsApiError && err.status === 400) {
          setError(`Geçersiz veri: ${err.detail || err.message}`);
        } else {
          setError(/** @type {Error} */ (err).message);
        }
      }
    });
  };

  return (
    <div className="inkly-create-card" style={createCardStyle}>
      <button
        type="button"
        onClick={() => setIsOpen((v) => !v)}
        aria-expanded={isOpen}
        style={createToggleStyle}
      >
        <span style={createPlusStyle} aria-hidden="true">＋</span>
        <span>Yeni {collectionKey} ekle</span>
        {draftData ? <span style={draftBadgeStyle}>taslak</span> : null}
        <span
          style={{
            display: "inline-flex",
            color: TEXT_MUTED,
            marginLeft: "auto",
            transition: "transform 220ms cubic-bezier(0.32, 0.72, 0.18, 1)",
            transform: isOpen ? "rotate(180deg)" : "rotate(0deg)",
          }}
        >
          <ChevronDown size={13} />
        </span>
      </button>

      <div
        className={`inkly-collapse${isOpen ? " is-open" : ""}`}
        aria-hidden={!isOpen}
      >
        <div style={createBodyStyle}>
          <CollectionFieldsForm
            fields={schema.fields}
            values={values}
            onChange={setValues}
            disabled={isPending}
          />
          {error ? <div style={errorInlineStyle}>{error}</div> : null}
          <div style={createActionsRowStyle}>
            <button
              type="button"
              onClick={submit}
              disabled={isPending}
              style={primaryButtonStyle}
            >
              {isPending ? "Oluşturuluyor…" : "Oluştur"}
            </button>
            {draftData ? (
              <button
                type="button"
                onClick={undoDraft}
                disabled={isPending}
                className="inkly-icon-button"
                style={blockResetStyle}
                aria-label="Form değerlerini sıfırla"
                title="Form değerlerini sıfırla"
              >
                <Undo2 size={13} />
              </button>
            ) : null}
            <span style={draftStatusStyle(draftStatus)}>{draftStatusLabel(draftStatus)}</span>
            <button
              type="button"
              onClick={() => { setIsOpen(false); reset(); }}
              disabled={isPending}
              className="inkly-btn-ghost"
              style={btnGhostStyle}
            >
              İptal
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

/** @param {"idle"|"saving"|"saved"|"failed"} status */
function draftStatusLabel(status) {
  if (status === "saving") return "Taslak kaydediliyor…";
  if (status === "saved") return "Taslak kaydedildi";
  if (status === "failed") return "Taslak kaydedilemedi";
  return "";
}

/** @param {"idle"|"saving"|"saved"|"failed"} status */
function draftStatusStyle(status) {
  /** @type {React.CSSProperties} */
  const base = {
    marginLeft: "auto",
    fontSize: 11,
    fontFamily: FONT_MONO,
    color: TEXT_MUTED,
    minHeight: 14,
  };
  if (status === "saved") return { ...base, color: "rgb(150, 210, 160)" };
  if (status === "failed") return { ...base, color: "#ff8b8b" };
  return base;
}

